// The previous attempt's `assert forall` blocks picked low-confidence triggers
// (e.g. `pre_self_.container_dom().contains(c_ptr)`), which do NOT match the
// ensures triggers (`post1_self_.get_container(container_ptr)` and
// `post2_self_.get_container(container_ptr)`), so the two ensures-foralls
// never got instantiated together. Repair: pin each `assert forall` to the
// same triggers the ensures use, and instantiate each ensures-forall by name
// inside the body so both post-states are constrained at the same key.

let target_ep = pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap();

// Domain equalities (both posts agree with pre).
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() =~= post2_self_.endpoint_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());

assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// Procs: pointwise equality between the two posts. The ensures triggers are
// `post1_self_.get_proc(p_ptr)` and `post2_self_.get_proc(p_ptr)`, so attach
// both as explicit triggers here.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

// Containers: pointwise equality between the two posts. Ensures triggers are
// `post1_self_.get_container(c)` and `post2_self_.get_container(c)`.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
        implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
}

// Non-target threads: pointwise equality. The ensures trigger is shared:
// `pre_self_.get_thread(t_ptr)`. Naming it once instantiates both ensures.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
        implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
}

// Non-target endpoints: pointwise equality. Ensures triggers are
// `post1_self_.get_endpoint(e)` and `post2_self_.get_endpoint(e)`.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_ep
        implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
    assert(post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
}

// Target thread fields agree between the two posts.
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post1_self_.get_thread(thread_ptr).ipc_payload
    =~= post2_self_.get_thread(thread_ptr).ipc_payload);
assert(post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post1_self_.get_thread(thread_ptr).state
    == post2_self_.get_thread(thread_ptr).state);

// Target endpoint fields agree between the two posts.
assert(post1_self_.get_endpoint(target_ep).queue_state == queue_state);
assert(post2_self_.get_endpoint(target_ep).queue_state == queue_state);
assert(post1_self_.get_endpoint(target_ep).queue_state
    == post2_self_.get_endpoint(target_ep).queue_state);
assert(post1_self_.get_endpoint(target_ep).owning_threads
    == pre_self_.get_endpoint(target_ep).owning_threads);
assert(post2_self_.get_endpoint(target_ep).owning_threads
    == pre_self_.get_endpoint(target_ep).owning_threads);
assert(post1_self_.get_endpoint(target_ep).owning_threads
    == post2_self_.get_endpoint(target_ep).owning_threads);
assert(post1_self_.get_endpoint(target_ep).queue@
    == pre_self_.get_endpoint(target_ep).queue@.push(thread_ptr));
assert(post2_self_.get_endpoint(target_ep).queue@
    == pre_self_.get_endpoint(target_ep).queue@.push(thread_ptr));
assert(post1_self_.get_endpoint(target_ep).queue@
    =~= post2_self_.get_endpoint(target_ep).queue@);

// Strengthen pointwise equalities to full equality (==), so the det_*_equal
// predicate that compares post-states accessor-by-accessor (very likely
// using `==`) discharges in a single shot.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr) == post2_self_.get_proc(p_ptr) by {
    assert(post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr));
}
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
        implies post1_self_.get_container(c_ptr) == post2_self_.get_container(c_ptr) by {
    assert(post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr));
}
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr), post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr)
        implies post1_self_.get_thread(t_ptr) == post2_self_.get_thread(t_ptr) by {
    if t_ptr == thread_ptr {
        assert(post1_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post2_self_.get_thread(t_ptr).endpoint_descriptors);
        assert(post1_self_.get_thread(t_ptr).ipc_payload
            =~= post2_self_.get_thread(t_ptr).ipc_payload);
        assert(post1_self_.get_thread(t_ptr).state
            == post2_self_.get_thread(t_ptr).state);
        assert(post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    } else {
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
        assert(post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    }
}
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr)
        implies post1_self_.get_endpoint(e_ptr) == post2_self_.get_endpoint(e_ptr) by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    if e_ptr == target_ep {
        assert(post1_self_.get_endpoint(e_ptr).queue_state
            == post2_self_.get_endpoint(e_ptr).queue_state);
        assert(post1_self_.get_endpoint(e_ptr).owning_threads
            == post2_self_.get_endpoint(e_ptr).owning_threads);
        assert(post1_self_.get_endpoint(e_ptr).queue@
            =~= post2_self_.get_endpoint(e_ptr).queue@);
        assert(post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
    } else {
        assert(post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
        assert(post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
        assert(post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
    }
}

// The two unit returns are trivially equal.
assert(r1 == r2);
